                     }
                     else
                     {
                         AddObjectTag(name, value);
                     }
                 }
             }

             private IReadOnlyList<Activity> GetDiagnosticSourceLinkCollection()
             {
                 if (_links == null)
                 {
                     return Array.Empty<Activity>();
                 }

                 var linkCollection = new List<Activity>();

                 foreach (var link in _links)
                 {
